ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?start_year WHERE {
  ?r a :Reporters .
  ?s a :Stories .
  ?s p:hasReporters ?r .
  ?r p:Start_Year ?start_year .
  ?s p:PublishDate ?publishdate_x .
  { SELECT (MAX(?m0) AS ?m) WHERE { ?s0 p:PublishDate ?m0 } }
  FILTER(STR(?publishdate_x) = STR(?m))
} }
  component_2: { SELECT ?start_month WHERE {
  ?r a :Reporters .
  ?s a :Stories .
  ?s p:hasReporters ?r .
  ?r p:Start_Month ?start_month .
  ?s p:PublishDate ?publishdate_x .
  { SELECT (MAX(?m0) AS ?m) WHERE { ?s0 p:PublishDate ?m0 } }
  FILTER(STR(?publishdate_x) = STR(?m))
} }
  full: { SELECT ?start_year ?start_month WHERE {
  ?r a :Reporters .
  ?s a :Stories .
  ?s p:hasReporters ?r .
  ?r p:Start_Year ?start_year .
  ?r p:Start_Month ?start_month .
  ?s p:PublishDate ?publishdate_x .
  { SELECT (MAX(?m0) AS ?m) WHERE { ?s0 p:PublishDate ?m0 } }
  FILTER(STR(?publishdate_x) = STR(?m))
} }
}

PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?start_month WHERE {
  ?r a :Reporters .
  ?a a :Articles .
  ?a p:hasReporters ?r .
  ?r p:Start_Month ?start_month .
  ?a p:Title ?title_f .
  FILTER(STR(?title_f) = "Climate Change: A Global Crisis")
} }
  component_2: { SELECT ?start_year WHERE {
  ?r a :Reporters .
  ?a a :Articles .
  ?a p:hasReporters ?r .
  ?r p:Start_Year ?start_year .
  ?a p:Title ?title_f .
  FILTER(STR(?title_f) = "Climate Change: A Global Crisis")
} }
  full: { SELECT ?start_year ?start_month WHERE {
  ?r a :Reporters .
  ?a a :Articles .
  ?a p:hasReporters ?r .
  ?r p:Start_Year ?start_year .
  ?r p:Start_Month ?start_month .
  ?a p:Title ?title_f .
  FILTER(STR(?title_f) = "Climate Change: A Global Crisis")
} }
}
